#include <iostream>
#include <string>
#include <vector>

using namespace std;

class TrieNode {
public:
    TrieNode* children[26];

    TrieNode() {
        for (int i = 0; i < 26; i++)
            children[i] = nullptr;
    }
};

class Solution {
public:
    bool insert(TrieNode* root, int depth, string word) {
        if (word.empty())
            return true;

        int idx = word[0] - 'a';
        if (root->children[idx] == nullptr)
            root->children[idx] = new TrieNode();

        return insert(root->children[idx], depth + 1, word.substr(1));
    }
};

int main() {
    Solution solution;
    string word;
    cin >> word;
    solution.insert(nullptr, 0, word);
    return 0;
}
